module top_module(
    input wire [7:0] operand_a,
    input wire [7:0] num2,
    input wire [1:0] opcode,
    output reg [7:0] result
);always @(*) begin
    case(opcode)
        2'b00: result = operand_a + num2;
        2'b01: result = operand_a - num2;
        2'b10: result = operand_a * num2;
        2'b11: result = operand_a / num2;
    endcase
end

endmodule
